def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 7:
            base = np.exp(ratio - 7)
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    factor = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    trig = np.sin(ratio * b / (a + 2)) - np.cos(ratio * a / (b + 1))
                    priority += factor * trig * base ** 1.7
            priority += np.tanh(base) * 15
        elif 4 < ratio <= 7:
            priority = np.log(ratio) * 8
            for m in range(1, int(np.ceil(ratio)) + 4):
                for n in range(1, m + 3):
                    term1 = ((ratio - m) ** 4) * np.cos(ratio * n)
                    term2 = np.sin(ratio * m) / (n + 1)
                    priority += np.tanh(term1 * term2) * 1.4
            priority -= np.exp(-(ratio - 4)) * 3
        elif 2 < ratio <= 4:
            s_cos, s_sin = 0, 0
            for r in range(1, 15):
                s_cos += ((ratio - 2) ** r) / (r * 2.3) * np.cos(r * ratio * 1.2)
                s_sin += ((ratio - 2) ** r) / (r * 1.7) * np.sin(r * ratio * 0.8)
            priority = (s_cos - s_sin) * np.tanh(5 * (4 - ratio)) + np.log(ratio) * 4
            priority += np.sin(ratio * i) * 0.8
        elif 1 <= ratio <= 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 3 + 1) * np.sin(n * ratio * 3)
            penalty = 0
            if bin_cap < item * 0.95:
                penalty = np.exp(-item / (bin_cap + 0.1)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty - np.log(ratio + 0.1) * 6
            for m in range(1, 6):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for p in range(1, 18):
                s += ((1 - ratio) ** p) / (p * 3.5 + 1) * np.cos(p * item * 0.9)
            if (i + int(item * 2)) % 5 == 0:
                priority = s * np.log1p(bin_cap + 5) * 1.5
            else:
                priority = s / (np.sqrt(bin_cap + 2) + 3)
            for q in range(1, 7):
                priority += ((1 - ratio) ** q) * np.sin(q * ratio * 2) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.sin(k * ratio * 3.1)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.sin(item * u * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if bin_cap % 7 == 0:
            priority += np.tanh(bin_cap * 0.1) * 2
        else:
            priority -= np.tanh(item * 0.05) * 2
        priorities[i] = priority
    return priorities
